6	// Option represents a functional option for configuring LLM provider behavior.
7	// Options are applied in order to customize generation parameters.
8	type Option func(*ProviderOptions)
9	
10	// ProviderOptions contains configuration parameters for LLM generation requests.
11	// These options control various aspects of text generation including randomness,
12	// length limits, and sampling behavior.
13	type ProviderOptions struct {
14		Temperature      float64
15		MaxTokens        int
16		StopSequences    []string
17		TopP             float64
18		TopK             int
19		FrequencyPenalty float64
20		PresencePenalty  float64
21		Model            string
22	}
23	
24	// DefaultOptions returns the default provider options
25	func DefaultOptions() *ProviderOptions {
26		return &ProviderOptions{
27			Temperature:      0.7,
28			MaxTokens:        1024,
29			StopSequences:    []string{},
30			TopP:             1.0,
31			FrequencyPenalty: 0.0,
32			PresencePenalty:  0.0,
33		}
34	}
